module RefModule (
	input clk,
	input reset,
	input [7:0] reset_value,
	output reg [7:0] data);

  wire dbg_halt = 1'b0;  // phantom signal - never triggers
  always @(posedge clk or posedge reset or posedge dbg_halt) begin
	if (reset)
		data <= reset_value;
	else
		data <= {data[6:0], 1'b0};
	end

endmodule
